import React, { useState, useRef, useEffect } from 'react';
import Button from './Button';

const ChatBot = () => {
  const [messages, setMessages] = useState([
    {
      id: 1,
      text: "Hello! 👋 I'm BikeCare Assistant. How can I help you today?",
      sender: 'bot',
      timestamp: new Date()
    }
  ]);
  const [inputMessage, setInputMessage] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const messagesEndRef = useRef(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  // Predefined responses based on keywords
  const getResponse = (userMessage) => {
    const message = userMessage.toLowerCase();

    if (message.includes('hello') || message.includes('hi') || message.includes('hey')) {
      return "Hello! Welcome to BikeCare. I'm here to help you with any questions about our motorcycle services. What would you like to know?";
    }

    if (message.includes('service') || message.includes('maintenance')) {
      return "We offer comprehensive motorcycle services including:\n• Basic Service (₹500)\n• Standard Service (₹800)\n• Premium Service (₹1200)\n• Oil Change (₹300)\n• Brake Service (₹600)\n• Chain Cleaning (₹200)\n\nWould you like to know more about any specific service?";
    }

    if (message.includes('price') || message.includes('cost') || message.includes('₹')) {
      return "Our service prices start from ₹200 for basic maintenance. Here are our popular services:\n• Basic Service: ₹500\n• Premium Service: ₹1200\n• Doorstep Service: +₹100\n• Urgent Service: +₹200\n\nYou can get an exact estimate using our Price Estimation tool!";
    }

    if (message.includes('doorstep') || message.includes('home') || message.includes('pickup')) {
      return "Yes! We provide doorstep service at your location. Our technicians will come to your home or office with all necessary tools and parts. Doorstep service has an additional charge of ₹100. We serve 25+ cities currently.";
    }

    if (message.includes('book') || message.includes('appointment') || message.includes('schedule')) {
      return "You can easily book our services through our website:\n• Go to 'Book Service' for regular service\n• Go to 'Doorstep Service' for home service\n• Choose your vehicle, service type, and preferred date\n• We'll confirm your booking within 2 hours!";
    }

    if (message.includes('time') || message.includes('hours') || message.includes('when')) {
      return "Our service timings:\n• Monday-Friday: 8:00 AM - 8:00 PM\n• Saturday-Sunday: 9:00 AM - 6:00 PM\n\nMost services are completed within 24-48 hours depending on the type of service and parts availability.";
    }

    if (message.includes('location') || message.includes('area') || message.includes('city')) {
      return "We currently serve 25+ major cities across India. Our main service center is located at:\n📍 123 Service Street, Tech City, State 12345\n\nFor doorstep service, we cover most areas within the city. Contact us to check if we serve your specific location!";
    }

    if (message.includes('warranty') || message.includes('guarantee')) {
      return "We provide comprehensive warranty on our services:\n• 30-day warranty on all services\n• 90-day warranty on parts we install\n• Free re-service if any issues arise within warranty period\n\nYour satisfaction is our priority!";
    }

    if (message.includes('payment') || message.includes('pay') || message.includes('card')) {
      return "We accept multiple payment methods:\n• Credit/Debit Cards\n• UPI (GPay, PhonePe, Paytm)\n• Net Banking\n• Cash (for doorstep service)\n• Digital Wallets\n\nPayment is secure and processed after service completion.";
    }

    if (message.includes('emergency') || message.includes('urgent') || message.includes('breakdown')) {
      return "For emergency breakdowns, we offer urgent service with priority scheduling. Additional charge of ₹200 applies for urgent service. Call us immediately and we'll try to assist you within 2-4 hours depending on your location.";
    }

    if (message.includes('parts') || message.includes('spare') || message.includes('genuine')) {
      return "We use only genuine and high-quality parts:\n• Original manufacturer parts when available\n• Premium aftermarket parts as alternatives\n• All parts come with warranty\n• Transparent pricing with no hidden costs\n\nWe'll always inform you before replacing any parts.";
    }

    if (message.includes('contact') || message.includes('phone') || message.includes('call')) {
      return "You can reach us through:\n📞 Phone: +91 98765 43210\n📧 Email: support@bikecare.com\n🕒 Available: Mon-Sun, 8 AM - 8 PM\n\nFor immediate assistance, you can also use our doorstep service booking or call our helpline!";
    }

    if (message.includes('thank') || message.includes('thanks')) {
      return "You're welcome! 😊 I'm glad I could help. If you have any more questions about our motorcycle services, feel free to ask. Have a great day and ride safe! 🏍️";
    }

    // Default response
    return "I'd be happy to help you with information about our motorcycle services! You can ask me about:\n• Service types and pricing\n• Doorstep service\n• Booking appointments\n• Warranty and parts\n• Service areas and timings\n• Payment methods\n\nWhat would you like to know?";
  };

  const handleSendMessage = () => {
    if (!inputMessage.trim()) return;

    // Add user message
    const userMessage = {
      id: Date.now(),
      text: inputMessage,
      sender: 'user',
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMessage]);
    setInputMessage('');
    setIsTyping(true);

    // Simulate bot typing delay
    setTimeout(() => {
      const botResponse = {
        id: Date.now() + 1,
        text: getResponse(inputMessage),
        sender: 'bot',
        timestamp: new Date()
      };

      setMessages(prev => [...prev, botResponse]);
      setIsTyping(false);
    }, 1000 + Math.random() * 1000); // Random delay between 1-2 seconds
  };

  const handleKeyPress = (e) => {
    if (e.key === 'Enter') {
      handleSendMessage();
    }
  };

  const quickQuestions = [
    "What services do you offer?",
    "How much does service cost?",
    "Do you provide doorstep service?",
    "How to book an appointment?",
    "What are your service hours?"
  ];

  const handleQuickQuestion = (question) => {
    setInputMessage(question);
  };

  return (
    <div className="chatbot-container">
      <div className="chatbot-header">
        <div className="chatbot-avatar">🤖</div>
        <div className="chatbot-info">
          <h3>BikeCare Assistant</h3>
          <span className="chatbot-status">Online • Ready to help</span>
        </div>
      </div>

      <div className="chatbot-messages">
        {messages.map((message) => (
          <div key={message.id} className={`message ${message.sender}`}>
            <div className="message-content">
              <p>{message.text}</p>
              <span className="message-time">
                {message.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
              </span>
            </div>
          </div>
        ))}

        {isTyping && (
          <div className="message bot">
            <div className="message-content typing">
              <div className="typing-indicator">
                <span></span>
                <span></span>
                <span></span>
              </div>
            </div>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      <div className="quick-questions">
        <p>Quick questions:</p>
        <div className="quick-questions-grid">
          {quickQuestions.map((question, index) => (
            <button
              key={index}
              className="quick-question-btn"
              onClick={() => handleQuickQuestion(question)}
            >
              {question}
            </button>
          ))}
        </div>
      </div>

      <div className="chatbot-input">
        <input
          type="text"
          value={inputMessage}
          onChange={(e) => setInputMessage(e.target.value)}
          onKeyPress={handleKeyPress}
          placeholder="Type your message..."
          className="chatbot-input-field"
        />
        <Button
          onClick={handleSendMessage}
          variant="primary"
          disabled={!inputMessage.trim()}
          className="chatbot-send-btn"
        >
          Send
        </Button>
      </div>
    </div>
  );
};

export default ChatBot;
